#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *R = (long long*)malloc(sizeof(long long) * N);
        long long totalSum = 0, negSum = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &R[i]);
            totalSum += R[i];
            if (R[i] < 0) negSum += R[i];
        }
        int start, end;
        scanf("%d %d", &start, &end);
        start--; end--; // zero based
        long long cw = 0;
        int i = start;
        while (i != end) {
            cw += R[i];
            i = (i + 1) % N;
        }
        long long ccw = totalSum - cw;
        long long best = cw < ccw ? cw : ccw;
        long long ans = best + 2 * negSum;
        printf("%lld\n", ans);
        free(R);
    }
    return 0;
}

