#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int N; cin>>N;
        vector<long long> R(N);
        long long totalSum=0, negSum=0;
        for(int i=0;i<N;++i){
            cin>>R[i];
            totalSum+=R[i];
            if(R[i]<0) negSum+=R[i];
        }
        int start,end; cin>>start>>end; --start; --end;
        long long cw=0;
        for(int i=start; i!=end; i=(i+1)%N) cw+=R[i];
        long long ccw=totalSum-cw;
        long long best=min(cw,ccw);
        long long ans=best+2*negSum;
        cout<<ans<<"\n";
    }
    return 0;
}
